@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@500;600;700;800&family=Inter:wght@400;500;600;700&display=swap');
@tailwind base;
@tailwind components;
@tailwind utilities;

html {
  scroll-behavior: smooth;
}

body {
  @apply bg-stone-50 text-zinc-900 dark:bg-zinc-950 dark:text-white;
}

@layer base {
  :root {
    color-scheme: light;
  }

  .dark {
    color-scheme: dark;
  }

  h1, h2, h3, h4, h5, h6 {
    font-family: 'Outfit', sans-serif;
  }

  body, p, li, input, textarea, select, button {
    font-family: 'Inter', sans-serif;
  }
}

@layer components {
  .site-shell {
    @apply min-h-screen bg-stone-50 text-zinc-900 transition-colors duration-300 dark:bg-zinc-950 dark:text-white;
  }

  .section {
    @apply py-20 md:py-28;
  }

  .section-inner {
    @apply max-w-7xl mx-auto px-4 sm:px-6 lg:px-8;
  }

  .section-head {
    @apply mb-12 md:mb-16;
  }

  .section-label {
    @apply mb-3 text-xs font-semibold uppercase tracking-widest text-emerald-600 dark:text-emerald-400;
  }

  .section-title {
    @apply text-3xl md:text-5xl font-semibold tracking-tight leading-tight text-zinc-900 dark:text-white;
  }

  .section-copy {
    @apply mt-4 max-w-2xl text-base md:text-lg leading-relaxed text-zinc-600 dark:text-zinc-400;
  }

  .card {
    @apply rounded-2xl border border-zinc-200 bg-white p-6 shadow-lg transition-all duration-300 hover:-translate-y-2 hover:shadow-2xl dark:border-zinc-800 dark:bg-zinc-900 md:p-8;
  }

  .glass-card {
    @apply rounded-2xl border border-white/20 bg-white/70 p-6 shadow-xl backdrop-blur-md dark:border-white/10 dark:bg-zinc-900/70 md:p-8;
  }

  .btn-primary {
    @apply inline-flex items-center justify-center gap-2 rounded-full bg-emerald-600 px-8 py-4 font-semibold text-white shadow-lg transition-all duration-200 hover:-translate-y-0.5 hover:scale-105 hover:bg-emerald-500;
  }

  .btn-secondary {
    @apply inline-flex items-center justify-center gap-2 rounded-full border-2 border-emerald-600 px-8 py-4 font-semibold text-emerald-700 transition-all duration-200 hover:-translate-y-0.5 hover:bg-emerald-50 dark:border-emerald-400 dark:text-emerald-300 dark:hover:bg-zinc-800;
  }

  .nav-wrap {
    @apply sticky top-0 z-50 border-b border-zinc-200/70 bg-stone-50/80 backdrop-blur-md dark:border-zinc-800/70 dark:bg-zinc-950/80;
  }

  .nav-link {
    @apply relative text-sm font-medium text-zinc-700 transition-all duration-200 after:absolute after:left-0 after:top-full after:h-0.5 after:w-full after:origin-left after:scale-x-0 after:bg-emerald-600 after:transition-transform after:duration-200 hover:text-emerald-600 hover:after:scale-x-100 dark:text-zinc-300 dark:hover:text-emerald-400;
  }

  .hero-shell {
    @apply relative min-h-screen overflow-hidden bg-gradient-to-br from-emerald-100 via-stone-50 to-amber-50 dark:from-zinc-950 dark:via-zinc-900 dark:to-emerald-950;
  }

  .hero-grid {
    @apply grid min-h-screen items-center gap-10 lg:grid-cols-5;
  }

  .hero-copy {
    @apply lg:col-span-3;
  }

  .hero-visual {
    @apply lg:col-span-2;
  }

  .trust-pill {
    @apply inline-flex items-center gap-2 rounded-full border border-emerald-200 bg-white/80 px-4 py-2 text-sm font-medium text-emerald-700 shadow-sm backdrop-blur dark:border-emerald-900 dark:bg-zinc-900/80 dark:text-emerald-300;
  }

  .eyebrow-badge {
    @apply inline-flex items-center gap-2 rounded-full bg-emerald-600/10 px-3 py-1 text-xs font-semibold uppercase tracking-widest text-emerald-700 dark:text-emerald-300;
  }

  .feature-icon {
    @apply flex h-10 w-10 items-center justify-center rounded-xl bg-emerald-100 text-emerald-600 dark:bg-emerald-950 dark:text-emerald-400;
  }

  .metric-card {
    @apply rounded-2xl border border-zinc-200 bg-white p-6 text-center shadow-lg dark:border-zinc-800 dark:bg-zinc-900;
  }

  .testimonial-stars {
    @apply mb-4 flex items-center gap-1 text-amber-400;
  }

  .input-field {
    @apply w-full rounded-2xl border border-zinc-300 bg-white px-4 py-3 text-zinc-900 outline-none transition-all duration-200 placeholder:text-zinc-400 focus:border-emerald-500 focus:ring-4 focus:ring-emerald-100 dark:border-zinc-700 dark:bg-zinc-950 dark:text-white dark:placeholder:text-zinc-500 dark:focus:ring-emerald-950;
  }

  .label-text {
    @apply mb-2 block text-sm font-semibold text-zinc-700 dark:text-zinc-300;
  }

  .footer-link {
    @apply text-zinc-600 transition-all duration-200 hover:text-emerald-600 dark:text-zinc-400 dark:hover:text-emerald-400;
  }

  .page-hero {
    @apply relative overflow-hidden bg-gradient-to-br from-emerald-100 via-stone-50 to-amber-50 py-24 dark:from-zinc-950 dark:via-zinc-900 dark:to-emerald-950 min-h-[40vh] flex items-center;
  }

  .brand-strip {
    @apply grid grid-cols-2 gap-4 md:grid-cols-4 lg:grid-cols-6;
  }

  .brand-chip {
    @apply rounded-2xl border border-zinc-200 bg-white px-4 py-4 text-center text-sm font-semibold text-zinc-500 shadow-sm dark:border-zinc-800 dark:bg-zinc-900 dark:text-zinc-400;
  }

  .number-step {
    @apply text-5xl font-bold tracking-tighter text-emerald-600 dark:text-emerald-400;
  }

  .list-copy {
    @apply space-y-3 text-base leading-relaxed text-zinc-600 dark:text-zinc-400;
  }

  .contact-mini {
    @apply flex items-start gap-3 rounded-2xl border border-zinc-200 bg-white p-5 shadow-sm dark:border-zinc-800 dark:bg-zinc-900;
  }

  .animate-soft {
    animation: floatSoft 6s ease-in-out infinite;
  }

  .gradient-animate {
    background-size: 200% 200%;
    animation: gradientShift 12s ease infinite;
  }
}

@keyframes floatSoft {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-10px); }
}

@keyframes gradientShift {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

.animate-in {
  animation: fadeInDown 0.2s ease-out;
}

.slide-in-from-top {
  animation: fadeInDown 0.2s ease-out;
}

@keyframes fadeInDown {
  from {
    opacity: 0;
    transform: translateY(-8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

