'use client'

import { useEffect, useState } from 'react'

const stats = [
  { label: 'Patients helped', value: 2800, suffix: '+' },
  { label: 'Average review rating', value: 5, suffix: '/5' },
  { label: 'Years of clinical experience', value: 14, suffix: '+' },
  { label: 'Same-week appointments', value: 97, suffix: '%' },
]

export default function StatsSection() {
  const [counts, setCounts] = useState(stats.map(() => 0))

  useEffect(() => {
    const interval = setInterval(() => {
      setCounts((prev) => prev.map((count, index) => {
        const target = stats[index].value
        const increment = Math.max(1, Math.ceil(target / 20))
        return count + increment >= target ? target : count + increment
      }))
    }, 60)

    return () => clearInterval(interval)
  }, [])

  return (
    <section className="section bg-emerald-600 text-white dark:bg-emerald-700">
      <div className="section-inner">
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
          {stats.map((stat, index) => (
            <div key={stat.label} className="metric-card bg-white/10 text-white dark:bg-white/5 border-white/20">
              <div className="text-4xl md:text-5xl font-bold tracking-tighter">{counts[index]}{stat.suffix}</div>
              <p className="mt-3 text-base leading-relaxed text-white/80" data-edit-id={`stat-${index + 1}`}>{stat.label}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

