export async function POST(request) {
  const { name, phone, email, preferredDate, preferredTime, reason } = await request.json()
  if (!name || !phone || !email || !preferredDate || !preferredTime || !reason) {
    return Response.json({ success: false, error: 'All booking fields are required.' }, { status: 400 })
  }

  return Response.json({
    success: true,
    message: `Thanks ${name}! Your appointment request for ${preferredDate} at ${preferredTime} has been received. Our team will contact you shortly.`
  })
}

